mapper.select:
SELECT id, name, description, price, stock_quantity, category, image_url, status, created_at, updated_at
FROM products
WHERE id = #{id}

mapper.sql:
WHERE status = 'ACTIVE'

    AND (name LIKE #{keyword} OR description LIKE #{keyword})


    AND category = #{category}


    AND price >= #{minPrice}


    AND price <= #{maxPrice}

mapper.select:
SELECT id, name, description, price, stock_quantity, category, image_url, status, created_at, updated_at FROM products
ORDER BY price ASC ORDER BY price DESC ORDER BY name ASC ORDER BY name DESC ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}
